# degradation_mode.py — circuit breaker with graceful degradation for Tier 1
import anthropic
from enum import Enum
import time

class CircuitState(Enum):
    CLOSED = "closed"        # normal operation
    OPEN = "open"            # degraded mode active
    HALF_OPEN = "half_open"  # testing recovery

class ClaudeCircuitBreaker:
    def __init__(self, failure_threshold=5, recovery_timeout=60):
        self.state = CircuitState.CLOSED
        self.failures = 0
        self.failure_threshold = failure_threshold
        self.recovery_timeout = recovery_timeout
        self.last_failure_time: float = 0

    def call(self, client: anthropic.Anthropic, **kwargs):
        if self.state == CircuitState.OPEN:
            if time.monotonic() - self.last_failure_time > self.recovery_timeout:
                self.state = CircuitState.HALF_OPEN
            else:
                return self._degraded_response()  # serve fallback immediately

        try:
            result = client.messages.create(**kwargs)
            self._on_success()
            return result
        except (anthropic.APIStatusError, anthropic.APIConnectionError) as e:
            self._on_failure()
            if self.state == CircuitState.OPEN:
                return self._degraded_response()
            raise

    def _on_success(self):
        self.failures = 0
        self.state = CircuitState.CLOSED

    def _on_failure(self):
        self.failures += 1
        self.last_failure_time = time.monotonic()
        if self.failures >= self.failure_threshold:
            self.state = CircuitState.OPEN

    def _degraded_response(self):
        return {"degraded": True, "message": "AI features are temporarily unavailable. Your request has been queued."}
